"""
Answer - paradigm-agnostic answer representation. See docs/API_REFERENCE.md for examples.
"""
from dataclasses import dataclass, field
from typing import TYPE_CHECKING, Any, Dict, List, Optional

from .provenance import Provenance

if TYPE_CHECKING:
    from fitz_ai.core.answer_mode import AnswerMode

@dataclass
class Answer:

    text: str
    provenance: List[Provenance] = field(default_factory=list)
    mode: Optional["AnswerMode"] = None
    metadata: Dict[str, Any] = field(default_factory=dict)

    def __post_init__(self):
        if self.text is None:
            raise ValueError("Answer text cannot be None (use empty string for no answer)")

    @property
def token_usage(self) -> dict[str, int] | None:  # [SYNTAX ERROR: unexpected unindent]
        """Extracts token usage data from metadata."""
        return self.metadata.get("token_usage")

